/**
 * @module tracker_ui
 * @description Tracker UI: grid rendering, keyboard input, transport, song bar,
 * instrument panel, import/export wrappers. All DOM manipulation lives here.
 */
var TrackerUI = (function() {
    'use strict';

    var state, playback, engine;
    var currentSongSlot = 0;
    var selectedInst = 0;
    var selectedOp = 0;
    var NUM_CHANNELS, KEY_NOTE_MAP;
    var selectionChangeListeners = [];

    /**
     * @description Initialize the tracker UI. Wires playback callbacks, keyboard handler, builds TON selector, loads demo, and renders.
     * @param {Object} _state - TrackerState instance
     * @param {Object} _playback - Playback engine instance
     * @param {Object} _engine - Sound engine (SCSP) instance
     */
    function init(_state, _playback, _engine) {
        state = _state;
        playback = _playback;
        engine = _engine;
        NUM_CHANNELS = TrackerState.NUM_CHANNELS;
        KEY_NOTE_MAP = TrackerState.KEY_NOTE_MAP;

        // Wire up playback callbacks
        playback.onRowChange = function() { updatePlaybackCursor(); };
        playback.onStop = function() {
            document.getElementById('btn-play').classList.remove('active');
            renderGrid();
            renderSongBar();
        };

        // Wire up keyboard handler
        document.addEventListener('keydown', keyHandler);

        // Build TON selector and load demo
        buildTonSelector();
        if (typeof DEMO_MIDI_B64 !== 'undefined' && DEMO_MIDI_B64) {
            loadDemoMidi();
        }

        // Expose functions referenced by HTML onclick attributes
        var w = typeof window !== 'undefined' ? window : {};
        w.togglePlay = togglePlay;
        w.stopPlayback = stopPlayback;
        w.exportTON = exportTON;
        w.exportSEQ = exportSEQ;
        w.exportMIDI = exportMIDI;
        w.importMIDI = importMIDI;
        w.importSEQ = importSEQ;
        w.importTonForTracker = importTonForTracker;
        w.importTonInst = importTonInst;
        w.addSongSlot = addSongSlot;
        w.removeSongSlot = removeSongSlot;
        w.dupPattern = dupPattern;
        w.newPattern = newPattern;
        w.toggleInstPanel = toggleInstPanel;
        w.addInstrument = addInstrument;
        w.dupInstrument = dupInstrument;
        w.delInstrument = delInstrument;
        w.onTonSelect = onTonSelect;
        w.toggleMute = toggleMute;
        w.toggleSolo = toggleSolo;
        w.setPatternLength = setPatternLength;
        w.updateTempo = updateTempo;
        w.selectMidiInput = selectMidiInput;
        w.toggleMidiLive = toggleMidiLive;

        // Initial render
        renderAll();
        updateTempo();

        // Init MIDI input
        initMidi();
    }

    /** @description Convenience wrapper for TrackerState.createEmptyPattern.
     * @param {number} len - Pattern length in rows
     * @returns {Object} New empty pattern */
    function createEmptyPattern(len) { return TrackerState.createEmptyPattern(state, len); }

    /** @description Toggle mute on a channel; releases silenced channels via engine and re-renders.
     * @param {number} ch - Channel index */
    function toggleMute(ch) {
        const silenced = TrackerState.toggleMute(ch);
        for (const c of silenced) engine.releaseChannel(c);
        renderChannelHeaders();
        renderGrid();
    }

    /** @description Toggle solo on a channel; releases silenced channels via engine and re-renders.
     * @param {number} ch - Channel index */
    function toggleSolo(ch) {
        const silenced = TrackerState.toggleSolo(ch);
        for (const c of silenced) engine.releaseChannel(c);
        renderChannelHeaders();
        renderGrid();
    }


    // ═══════════════════════════════════════════════════════════════
    // PLAYBACK ENGINE
    // ═══════════════════════════════════════════════════════════════


    // ═══════════════════════════════════════════════════════════════
    // NOTE NAMES & KEYBOARD MAPPING
    // ═══════════════════════════════════════════════════════════════

    // NOTE_NAMES and noteName() loaded from tools/note_util.js


    /** @description Read current octave from DOM input.
     * @returns {number} Current octave (defaults to 4) */
    function getOctave() { return parseInt(document.getElementById('octave').value) || 4; }

    /** @description Read edit step from DOM input. Cursor advances by this many rows after note/off entry.
     * @returns {number} Edit step (defaults to 1, 0 = stay in place) */
    function getEditStep() { var v = parseInt(document.getElementById('edit-step').value); return isNaN(v) ? 1 : Math.max(0, v); }

    // ═══════════════════════════════════════════════════════════════
    // UI: GRID RENDERING
    // ═══════════════════════════════════════════════════════════════

    /** @description Render channel header row with mute/solo buttons and per-channel instrument selectors. */
    function renderChannelHeaders() {
        const el = document.getElementById('ch-headers');
        el.innerHTML = '';
        const pat = getCurrentPattern();
        for (let ch = 0; ch < NUM_CHANNELS; ch++) {
            const div = document.createElement('div');
            div.className = 'ch-hdr' + (TrackerState.getChannelState(ch) === 'muted' || (!TrackerState.isChannelAudible(ch) && TrackerState.getChannelState(ch) !== 'solo') ? ' muted' : '');
            div.innerHTML = '<span>CH' + (ch + 1) + '</span>';

            const muteBtn = document.createElement('button');
            muteBtn.className = 'ch-btn' + (TrackerState.getChannelState(ch) === 'muted' ? ' muted' : '');
            muteBtn.textContent = 'M';
            muteBtn.title = 'Mute';
            muteBtn.onclick = ((c) => () => toggleMute(c))(ch);
            div.appendChild(muteBtn);

            const soloBtn = document.createElement('button');
            soloBtn.className = 'ch-btn' + (TrackerState.getChannelState(ch) === 'solo' ? ' solo' : '');
            soloBtn.textContent = 'S';
            soloBtn.title = 'Solo';
            soloBtn.onclick = ((c) => () => toggleSolo(c))(ch);
            div.appendChild(soloBtn);

            const sel = document.createElement('select');
            state.instruments.forEach((inst, i) => {
                const opt = document.createElement('option');
                opt.value = i; opt.textContent = i.toString(16).toUpperCase().padStart(2, '0') + ':' + inst.name;
                if (i === pat.channels[ch].defaultInst) opt.selected = true;
                sel.appendChild(opt);
            });
            sel.onchange = () => { pat.channels[ch].defaultInst = parseInt(sel.value); };
            div.appendChild(sel);
            el.appendChild(div);
        }
    }

    /** @description Render the pattern grid with note/inst/vol cells, cursor highlight, and playback position. */
    function renderGrid() {
        const grid = document.getElementById('grid');
        grid.innerHTML = '';
        const pat = getCurrentPattern();
        const spb = state.stepsPerBeat;

        for (let r = 0; r < pat.length; r++) {
            const row = document.createElement('div');
            row.className = 'row';
            if (r % spb === 0) row.classList.add('beat');
            if (playback.playing && playback.currentRow === r) row.classList.add('playing');
            row.id = 'row-' + r;

            const numDiv = document.createElement('div');
            numDiv.className = 'row-num';
            numDiv.textContent = r.toString(16).toUpperCase().padStart(2, '0');
            numDiv.onclick = ((row) => () => { state.cursor.row = row; state.cursor.ch = 0; renderGrid(); })(r);
            row.appendChild(numDiv);

            for (let ch = 0; ch < NUM_CHANNELS; ch++) {
                const cell = pat.channels[ch].rows[r];
                const cellDiv = document.createElement('div');
                cellDiv.className = 'cell';
                if (state.cursor.row === r && state.cursor.ch === ch) cellDiv.classList.add('cursor');
                if (cell.note !== null) cellDiv.classList.add('has-note');
                if (!TrackerState.isChannelAudible(ch)) cellDiv.classList.add('ch-muted');
                cellDiv.dataset.row = r;
                cellDiv.dataset.ch = ch;

                let noteStr = '---';
                let noteClass = 'note';
                if (cell.note === -1) { noteStr = 'OFF'; noteClass = 'note off'; }
                else if (cell.note !== null) { noteStr = noteName(cell.note); }

                const instStr = cell.inst !== null ? cell.inst.toString(16).toUpperCase().padStart(2, '0') : '..';
                const volStr = cell.vol !== null ? cell.vol.toString(16).toUpperCase().padStart(2, '0') : '..';

                const isCursor = state.cursor.row === r && state.cursor.ch === ch;
                const nc = isCursor && state.cursor.col === 0 ? ' col-cursor' : '';
                const ic = isCursor && state.cursor.col === 1 ? ' col-cursor' : '';
                const vc = isCursor && state.cursor.col === 2 ? ' col-cursor' : '';
                cellDiv.innerHTML = '<span class="' + noteClass + nc + '">' + noteStr + '</span>' +
                                    '<span class="inst' + ic + '">' + instStr + '</span>' +
                                    '<span class="vol' + vc + '">' + volStr + '</span>';

                cellDiv.onclick = () => {
                    state.cursor.row = r;
                    state.cursor.ch = ch;
                    renderGrid();
                };

                row.appendChild(cellDiv);
            }
            grid.appendChild(row);
        }
        updateStatusBar();
    }

    /** @description Update playing row highlight and song slot indicator during playback. Switches song slot if playback has advanced. */
    function updatePlaybackCursor() {
        // Follow playback: switch to the currently-playing song slot
        if (playback.currentSongSlot !== currentSongSlot) {
            currentSongSlot = playback.currentSongSlot;
            renderSongBar();
            renderChannelHeaders();
            renderGrid();
        }

        // Update row highlight
        const rows = document.querySelectorAll('.row.playing');
        rows.forEach(r => r.classList.remove('playing'));
        const cur = document.getElementById('row-' + playback.currentRow);
        if (cur) {
            cur.classList.add('playing');
            cur.scrollIntoView({ block: 'nearest' });
        }

        // Update song slot highlight
        const slots = document.querySelectorAll('.song-slot.playing');
        slots.forEach(s => s.classList.remove('playing'));
        const songSlots = document.getElementById('song-slots').children;
        if (songSlots[playback.currentSongSlot]) {
            songSlots[playback.currentSongSlot].classList.add('playing');
        }
    }

    /** @description Update status bar with cursor position (row, column) and current instrument name. */
    function updateStatusBar() {
        const colNames = ['Note', 'Inst', 'Vol'];
        document.getElementById('status-pos').textContent = 'Row: ' + state.cursor.row.toString(16).toUpperCase().padStart(2, '0') + ' [' + colNames[state.cursor.col] + ']';
        const pat = getCurrentPattern();
        const instIdx = pat.channels[state.cursor.ch].defaultInst;
        document.getElementById('status-inst').textContent = 'Inst: ' + instIdx.toString(16).toUpperCase().padStart(2, '0') + ' ' + (state.instruments[instIdx] || {}).name;
    }

    /** @description Display a temporary status message that auto-clears after 3 seconds.
     * @param {string} msg - Message to display */
    function showStatus(msg) {
        document.getElementById('status-msg').textContent = msg;
        setTimeout(() => { document.getElementById('status-msg').textContent = ''; }, 3000);
    }

    // ═══════════════════════════════════════════════════════════════
    // KEYBOARD INPUT
    // ═══════════════════════════════════════════════════════════════

    /**
     * @description Main keyboard event handler: note input via piano-style key mapping, cursor navigation
     * (arrows/tab), hex digit entry for inst/vol columns, delete/backspace, and transport shortcuts (space).
     * @param {KeyboardEvent} e
     */
    async function keyHandler(e) {
        // Don't handle keys when focused on inputs
        if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT') return;

        const pat = getCurrentPattern();
        const cur = state.cursor;

        // Space = toggle play
        if (e.code === 'Space') {
            e.preventDefault();
            togglePlay();
            return;
        }

        // Navigation — Left/Right cycles: note → inst → vol → next channel
        if (e.key === 'ArrowDown') { e.preventDefault(); cur.row = Math.min(cur.row + 1, pat.length - 1); renderGrid(); return; }
        if (e.key === 'ArrowUp') { e.preventDefault(); cur.row = Math.max(cur.row - 1, 0); renderGrid(); return; }
        if (e.key === 'ArrowRight') {
            e.preventDefault();
            cur.col++;
            if (cur.col > 2) { cur.col = 0; cur.ch = Math.min(cur.ch + 1, NUM_CHANNELS - 1); }
            renderGrid(); return;
        }
        if (e.key === 'ArrowLeft') {
            e.preventDefault();
            cur.col--;
            if (cur.col < 0) { cur.col = 2; cur.ch = Math.max(cur.ch - 1, 0); }
            renderGrid(); return;
        }
        if (e.key === 'Tab') { e.preventDefault(); cur.ch = (cur.ch + (e.shiftKey ? -1 : 1) + NUM_CHANNELS) % NUM_CHANNELS; cur.col = 0; renderGrid(); return; }

        // Delete = clear cell
        if (e.key === 'Delete' || e.key === 'Backspace') {
            e.preventDefault();
            pat.channels[cur.ch].rows[cur.row] = { note: null, inst: null, vol: null };
            if (e.key === 'Backspace') { cur.row = Math.max(cur.row - getEditStep(), 0); }
            else { cur.row = Math.min(cur.row + getEditStep(), pat.length - 1); }
            renderGrid();
            return;
        }

        // Hex digit input for instrument (col=1) and volume (col=2) columns
        if (cur.col === 1 || cur.col === 2) {
            const hexDigit = '0123456789abcdef'.indexOf(e.key.toLowerCase());
            if (hexDigit >= 0) {
                e.preventDefault();
                const cell = pat.channels[cur.ch].rows[cur.row];
                if (cur.col === 1) {
                    // Instrument: two hex digits, shift left and add
                    const prev = cell.inst !== null ? cell.inst : 0;
                    cell.inst = ((prev & 0x0F) << 4) | hexDigit;
                    if (cell.inst >= state.instruments.length) cell.inst = state.instruments.length - 1;
                } else {
                    // Volume: two hex digits, shift left and add (0x00-0x7F)
                    const prev = cell.vol !== null ? cell.vol : 0;
                    cell.vol = Math.min(127, ((prev & 0x0F) << 4) | hexDigit);
                }
                renderGrid();
                return;
            }
        }

        // Note off (period key or backtick)
        if (e.key === '.' || e.key === '`') {
            e.preventDefault();
            pat.channels[cur.ch].rows[cur.row].note = -1;
            pat.channels[cur.ch].rows[cur.row].inst = null;
            cur.row = Math.min(cur.row + getEditStep(), pat.length - 1);
            renderGrid();
            return;
        }

        // Note entry
        const noteOffset = KEY_NOTE_MAP[e.key.toLowerCase()];
        if (noteOffset !== undefined) {
            e.preventDefault();
            const midi = getOctave() * 12 + noteOffset;
            if (midi < 0 || midi > 127) return;

            const cell = pat.channels[cur.ch].rows[cur.row];
            cell.note = midi;
            if (cell.inst === null) cell.inst = pat.channels[cur.ch].defaultInst;

            // Preview the note
            await engine.init();
            engine.startAudio(playback);
            if (cell.inst < state.instruments.length) {
                engine.triggerNote(cur.ch, midi, cell.inst, state.instruments[cell.inst]);
                setTimeout(() => engine.releaseChannel(cur.ch), 300);
            }

            cur.row = Math.min(cur.row + getEditStep(), pat.length - 1);
            renderGrid();
            return;
        }
    }

    // ═══════════════════════════════════════════════════════════════
    // TRANSPORT CONTROLS
    // ═══════════════════════════════════════════════════════════════

    /** @description Toggle playback start/stop. Initializes audio engine on first play. */
    async function togglePlay() {
        await engine.init();
        engine.startAudio(playback);
        if (playback.playing) {
            playback.stop();
        } else {
            playback.start(state.cursor.row, currentSongSlot);
            document.getElementById('btn-play').classList.add('active');
        }
    }

    /** @description Stop playback. */
    function stopPlayback() {
        playback.stop();
    }

    /** @description Read BPM and stepsPerBeat from DOM inputs, update state and playback engine. */
    function updateTempo() {
        state.bpm = parseInt(document.getElementById('bpm').value) || 120;
        state.stepsPerBeat = parseInt(document.getElementById('steps-per-beat').value) || 4;
        playback.updateTempo();
    }

    /** @description Read pattern length from DOM input and resize the current pattern. */
    function setPatternLength() {
        const newLen = parseInt(document.getElementById('pattern-length').value);
        TrackerState.resizePattern(state, currentSongSlot, newLen);
        renderGrid();
    }

    // ═══════════════════════════════════════════════════════════════
    // EXPORT
    // ═══════════════════════════════════════════════════════════════

    // ═══════════════════════════════════════════════════════════════
    // SONG ARRANGEMENT
    // ═══════════════════════════════════════════════════════════════


    /** @description Get the pattern index for the current song slot.
     * @returns {number} Pattern index */
    function getCurrentPatternIndex() { return TrackerState.getCurrentPatternIndex(state, currentSongSlot); }
    /** @description Get the pattern object for the current song slot.
     * @returns {Object} Pattern data */
    function getCurrentPattern() { return TrackerState.getCurrentPattern(state, currentSongSlot); }

    /** @description Render song arrangement slots with active/playing highlights and pattern usage info. */
    function renderSongBar() {
        const el = document.getElementById('song-slots');
        el.innerHTML = '';
        state.song.forEach((patIdx, i) => {
            const slot = document.createElement('div');
            slot.className = 'song-slot' + (i === currentSongSlot ? ' active' : '');
            if (playback.playing && playback.currentSongSlot === i) slot.classList.add('playing');
            slot.textContent = patIdx.toString(16).toUpperCase().padStart(2, '0');
            slot.onclick = () => { currentSongSlot = i; renderAll(); };
            el.appendChild(slot);
        });
        const usedPats = new Set(state.song);
        document.getElementById('pat-info').textContent =
            'Editing pat ' + getCurrentPatternIndex().toString(16).toUpperCase().padStart(2,'0') +
            ' | ' + usedPats.size + ' unique / ' + state.song.length + ' slots';
    }

    /** @description Add a new song slot after the current one, duplicating the current pattern reference. */
    function addSongSlot() {
        TrackerState.addSongSlot(state, currentSongSlot);
        renderSongBar();
    }

    /** @description Remove the current song slot and re-render. */
    function removeSongSlot() {
        currentSongSlot = TrackerState.removeSongSlot(state, currentSongSlot);
        renderAll();
    }

    /** @description Create a new empty pattern and assign it to a new song slot. */
    function newPattern() {
        currentSongSlot = TrackerState.newPattern(state, currentSongSlot);
        renderAll();
    }

    /** @description Duplicate the current pattern into a new song slot. */
    function dupPattern() {
        currentSongSlot = TrackerState.dupPattern(state, currentSongSlot);
        renderAll();
    }

    /** @description Re-render entire UI: song bar, channel headers, pattern grid, and instrument list. */
    function renderAll() {
        renderSongBar();
        renderChannelHeaders();
        renderGrid();
        renderInstList();
    }

    // ═══════════════════════════════════════════════════════════════
    // INSTRUMENT PANEL
    // ═══════════════════════════════════════════════════════════════


    /** @description Collapse or expand the instrument panel sidebar. */
    function toggleInstPanel() {
        const panel = document.getElementById('inst-panel');
        panel.classList.toggle('collapsed');
        const btn = document.getElementById('inst-toggle');
        btn.textContent = panel.classList.contains('collapsed') ? '>>' : 'Instruments \u00ab';
    }

    /** @description Render instrument list with selection highlight; double-click to rename. */
    function renderInstList() {
        const el = document.getElementById('inst-list');
        el.innerHTML = '';
        state.instruments.forEach((inst, i) => {
            const div = document.createElement('div');
            div.className = 'inst-item' + (i === selectedInst ? ' sel' : '');
            div.innerHTML = '<span><span class="inst-num">' + i.toString(16).toUpperCase().padStart(2, '0') + '</span>' + inst.name + '</span>' +
                            '<span style="color:#555;">' + inst.operators.length + 'op</span>';
            div.onclick = () => { selectedInst = i; selectedOp = 0; renderInstList(); renderInstEditor(); notifySelectionChange(); };
            div.ondblclick = () => {
                const name = prompt('Rename instrument:', inst.name);
                if (name) { inst.name = name; renderInstList(); renderChannelHeaders(); }
            };
            el.appendChild(div);
        });
        renderInstEditor();
    }

    /** @description Delegate instrument editor rendering to the sound engine. */
    function renderInstEditor() {
        const el = document.getElementById('inst-editor');
        const inst = state.instruments[selectedInst];
        engine.renderInstEditor(el, inst, selectedOp, function(opts) {
            if (opts && typeof opts.selectedOp === 'number') selectedOp = opts.selectedOp;
            renderInstList();
            notifySelectionChange();
        });
    }

    /** @description Add a new default instrument to the state and re-render. */
    function addInstrument() {
        var inst = { name: 'New ' + state.instruments.length,
            operators: [{ freq_ratio:1.0, freq_fixed:0, level:0.8, ar:31, d1r:0, dl:0, d2r:0, rr:14,
                          mdl:0, mod_source:-1, feedback:0, is_carrier:true, waveform:0,
                          loop_mode:1, loop_start:0, loop_end:1024 }] };
        selectedInst = TrackerState.addInstrument(state, inst);
        renderInstList(); renderChannelHeaders();
    }

    /** @description Duplicate the currently selected instrument. */
    function dupInstrument() {
        selectedInst = TrackerState.dupInstrument(state, selectedInst);
        renderInstList(); renderChannelHeaders();
    }

    /** @description Delete the currently selected instrument (always keeps at least one). */
    function delInstrument() {
        selectedInst = TrackerState.delInstrument(state, selectedInst);
        renderInstList(); renderChannelHeaders();
    }

    /** @description Open file dialog to import a TON file as individual instruments into the tracker state. */
    async function importTonInst() {
        if (!TonIO) { showStatus('TonIO not available'); return; }
        await engine.init(); engine.startAudio(playback);
        const input = document.createElement('input');
        input.type = 'file'; input.accept = '.ton,.TON';
        input.style.display = 'none';
        document.body.appendChild(input);
        input.onchange = (e) => {
            const file = e.target.files[0];
            document.body.removeChild(input);
            if (!file) return;
            const reader = new FileReader();
            reader.onload = (ev) => {
                try {
                    loadTonData(ev.target.result, file.name);
                    renderInstList(); renderChannelHeaders();
                } catch (err) { showStatus('TON error: ' + err.message); }
            };
            reader.readAsArrayBuffer(file);
        };
        input.click();
    }

    /* Recompute rawRegs from the current panel parameter values.
     * Called whenever the user edits an instrument parameter so that
     * programSlotRaw uses the updated values. */

    // ═══════════════════════════════════════════════════════════════
    // MIDI/SEQ IMPORT (parseMIDI from tools/midi_io.js, parseSEQ from tools/seq_io.js)
    // ═══════════════════════════════════════════════════════════════


    /** @description Open file dialog to import a MIDI file; parses and converts to tracker patterns via midiToPatterns. */
    function importMIDI() {
        const input = document.createElement('input');
        input.type = 'file'; input.accept = '.mid,.midi,.MID,.MIDI';
        input.style.display = 'none';
        document.body.appendChild(input);
        input.onchange = (e) => {
            const file = e.target.files[0];
            document.body.removeChild(input);
            if (!file) return;
            const reader = new FileReader();
            reader.onload = (ev) => {
                try {
                    const midi = parseMIDI(ev.target.result);
                    midiToPatterns(midi);
                    showStatus('Imported MIDI: ' + file.name);
                } catch (err) {
                    showStatus('MIDI error: ' + err.message);
                }
            };
            reader.readAsArrayBuffer(file);
        };
        input.click();
    }


    /**
     * @description Convert a parseSEQ result into tracker patterns. Maps SEQ channels to tracker channels,
     * quantizes events to step grid, and places note-on/off and program change data.
     * @param {Object} seq - Parsed SEQ data with resolution, bpm, and events array
     */
    function seqToPatterns(seq) {
        const ticksPerStep = seq.resolution / state.stepsPerBeat;

        // Set tempo
        state.bpm = seq.bpm;
        document.getElementById('bpm').value = state.bpm;

        const noteOns = seq.events.filter(e => e.type === 'on').sort((a, b) => a.absTime - b.absTime);
        if (noteOns.length === 0) { showStatus('No notes in SEQ'); return; }

        // Total length from note-ons + gate times
        let lastTime = 0;
        for (const ev of noteOns) {
            const end = ev.absTime + (ev.gate || 0);
            if (end > lastTime) lastTime = end;
        }
        const totalSteps = Math.ceil(lastTime / ticksPerStep) + 1;

        const patLen = state.patternLength;
        const numPatterns = Math.max(1, Math.ceil(totalSteps / patLen));

        // Map SEQ channels to tracker channels (max NUM_CHANNELS)
        const usedChannels = [...new Set(noteOns.map(e => e.ch))].sort((a, b) => a - b);
        const chMap = {};
        usedChannels.forEach((seqCh, i) => {
            if (i < NUM_CHANNELS) chMap[seqCh] = i;
        });

        // Create patterns
        state.patterns = [];
        state.song = [];
        for (let p = 0; p < numPatterns; p++) {
            state.patterns.push(createEmptyPattern(patLen));
            state.song.push(p);
        }

        // Place note-on events
        for (const ev of noteOns) {
            const trackerCh = chMap[ev.ch];
            if (trackerCh === undefined) continue;

            const globalStep = Math.round(ev.absTime / ticksPerStep);
            const patIdx = Math.floor(globalStep / patLen);
            const row = globalStep % patLen;

            if (patIdx >= state.patterns.length) continue;
            const cell = state.patterns[patIdx].channels[trackerCh].rows[row];
            cell.note = ev.note;
            cell.vol = ev.vel;

            // Place note-off from gate time
            if (ev.gate > 0) {
                const offStep = Math.round((ev.absTime + ev.gate) / ticksPerStep);
                const offPatIdx = Math.floor(offStep / patLen);
                const offRow = offStep % patLen;
                if (offPatIdx < state.patterns.length) {
                    const offCell = state.patterns[offPatIdx].channels[trackerCh].rows[offRow];
                    if (offCell.note === null) offCell.note = -1; // OFF marker
                }
            }
        }

        // Handle program changes
        const pcEvents = seq.events.filter(e => e.type === 'pc');
        for (const ev of pcEvents) {
            const trackerCh = chMap[ev.ch];
            if (trackerCh === undefined) continue;
            for (const pat of state.patterns) {
                if (ev.prog < state.instruments.length) {
                    pat.channels[trackerCh].defaultInst = ev.prog;
                }
            }
        }

        currentSongSlot = 0;
        state.cursor.row = 0;
        state.cursor.ch = 0;
        updateTempo();
        renderAll();
    }

    /** @description Open file dialog to import a Saturn SEQ file; parses and converts to tracker patterns via seqToPatterns. */
    function importSEQ() {
        const input = document.createElement('input');
        input.type = 'file'; input.accept = '.seq,.SEQ';
        input.style.display = 'none';
        document.body.appendChild(input);
        input.onchange = (e) => {
            const file = e.target.files[0];
            document.body.removeChild(input);
            if (!file) return;
            const reader = new FileReader();
            reader.onload = (ev) => {
                try {
                    const seq = parseSEQ(ev.target.result);
                    seqToPatterns(seq);
                    showStatus('Imported SEQ: ' + file.name);
                } catch (err) {
                    showStatus('SEQ error: ' + err.message);
                }
            };
            reader.readAsArrayBuffer(file);
        };
        input.click();
    }

    /** @description Open file dialog to import a TON bank file via engine.importBank (replaces all instruments). */
    async function importTonForTracker() {
        if (!TonIO) { showStatus('TonIO not available'); return; }
        await engine.init(); engine.startAudio(playback);
        const input = document.createElement('input');
        input.type = 'file'; input.accept = '.ton,.TON';
        input.style.display = 'none';
        document.body.appendChild(input);
        input.onchange = (e) => {
            const file = e.target.files[0];
            document.body.removeChild(input);
            if (!file) return;
            const reader = new FileReader();
            reader.onload = (ev) => {
                try {
                    loadTonData(ev.target.result, file.name);
                } catch (err) { showStatus('TON error: ' + err.message); }
            };
            reader.readAsArrayBuffer(file);
        };
        input.click();
    }

    /**
     * @description Convert a parseMIDI result into tracker patterns. Extracts tempo, maps MIDI channels
     * to tracker channels, quantizes note-on/off events to the step grid, and applies program changes.
     * @param {Object} midi - Parsed MIDI data with division and events array
     */
    function midiToPatterns(midi) {
        const division = midi.division; // ticks per beat
        const spb = state.stepsPerBeat;
        const ticksPerStep = division / spb;

        // Get tempo from first tempo event, or default 120
        const tempoEv = midi.events.find(e => e.type === 'tempo');
        if (tempoEv) {
            state.bpm = tempoEv.bpm;
            document.getElementById('bpm').value = state.bpm;
        }

        // Collect note-on and note-off events
        const noteOns = midi.events.filter(e => e.type === 'on').sort((a, b) => a.absTime - b.absTime);
        const noteOffs = midi.events.filter(e => e.type === 'off').sort((a, b) => a.absTime - b.absTime);
        if (noteOns.length === 0) { showStatus('No notes in MIDI'); return; }

        // Find total length in steps (include note-off times)
        const allTimes = [...noteOns.map(e => e.absTime), ...noteOffs.map(e => e.absTime)];
        const lastTime = Math.max(...allTimes);
        const totalSteps = Math.ceil(lastTime / ticksPerStep) + 1;

        // Split into patterns of patternLength
        const patLen = state.patternLength;
        const numPatterns = Math.max(1, Math.ceil(totalSteps / patLen));

        // Find which MIDI channels are used, map to tracker channels (max NUM_CHANNELS)
        const usedChannels = [...new Set(noteOns.map(e => e.ch))].sort((a, b) => a - b);
        const chMap = {}; // MIDI channel → tracker channel
        usedChannels.forEach((midiCh, i) => {
            if (i < NUM_CHANNELS) chMap[midiCh] = i;
        });

        // Create patterns
        state.patterns = [];
        state.song = [];
        for (let p = 0; p < numPatterns; p++) {
            state.patterns.push(createEmptyPattern(patLen));
            state.song.push(p);
        }

        // Place note-on events
        for (const ev of noteOns) {
            const trackerCh = chMap[ev.ch];
            if (trackerCh === undefined) continue;

            const globalStep = Math.round(ev.absTime / ticksPerStep);
            const patIdx = Math.floor(globalStep / patLen);
            const row = globalStep % patLen;

            if (patIdx >= state.patterns.length) continue;
            const cell = state.patterns[patIdx].channels[trackerCh].rows[row];
            cell.note = ev.note;
            cell.vol = ev.vel;
        }

        // Place note-off events (only where there isn't already a note-on at that position)
        for (const ev of noteOffs) {
            const trackerCh = chMap[ev.ch];
            if (trackerCh === undefined) continue;

            const globalStep = Math.round(ev.absTime / ticksPerStep);
            const patIdx = Math.floor(globalStep / patLen);
            const row = globalStep % patLen;

            if (patIdx >= state.patterns.length) continue;
            const cell = state.patterns[patIdx].channels[trackerCh].rows[row];
            // Only place OFF if the cell doesn't already have a note-on
            if (cell.note === null) {
                cell.note = -1; // OFF marker
            }
        }

        // Handle program changes — map to channel default instruments
        const pcEvents = midi.events.filter(e => e.type === 'pc');
        for (const ev of pcEvents) {
            const trackerCh = chMap[ev.ch];
            if (trackerCh === undefined) continue;
            // Set default instrument for this channel across all patterns
            for (const pat of state.patterns) {
                if (ev.prog < state.instruments.length) {
                    pat.channels[trackerCh].defaultInst = ev.prog;
                }
            }
        }

        currentSongSlot = 0;
        state.cursor.row = 0;
        state.cursor.ch = 0;
        updateTempo();
        renderAll();
    }

    // ═══════════════════════════════════════════════════════════════
    // EXPORT (buildSEQ from tools/seq_io.js, buildMIDI from tools/midi_io.js)
    // ═══════════════════════════════════════════════════════════════

    /** @description Export all instruments as a TON file and trigger browser download. */
    function exportTON() {
        if (!TonIO) { showStatus('TonIO not available'); return; }
        const tonData = TonIO.exportTon(state.instruments, SCSPEngine.generateWaveform);
        const blob = new Blob([tonData], { type: 'application/octet-stream' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'tracker.ton';
        a.click();
        URL.revokeObjectURL(a.href);
        showStatus('Exported TON (' + state.instruments.length + ' instruments)');
    }

    /** @description Export song as a Saturn SEQ file and trigger browser download. */
    function exportSEQ() {
        const seqData = buildSEQ({ patterns: state.patterns, song: state.song, bpm: state.bpm, stepsPerBeat: state.stepsPerBeat, numChannels: NUM_CHANNELS });
        if (!seqData) return;
        const blob = new Blob([seqData], { type: 'application/octet-stream' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'tracker.seq';
        a.click();
        URL.revokeObjectURL(a.href);
        showStatus('Exported SEQ (' + seqData.length + ' bytes)');
    }

    /** @description Export song as a Standard MIDI file and trigger browser download. */
    function exportMIDI() {
        const midiData = buildMIDI({ patterns: state.patterns, song: state.song, bpm: state.bpm, stepsPerBeat: state.stepsPerBeat, numChannels: NUM_CHANNELS });
        if (!midiData) return;
        const blob = new Blob([midiData], { type: 'audio/midi' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'tracker.mid';
        a.click();
        URL.revokeObjectURL(a.href);
        showStatus('Exported MIDI (' + midiData.length + ' bytes)');
    }


    // ═══════════════════════════════════════════════════════════════
    // EMBEDDED DEMO DATA
    // ═══════════════════════════════════════════════════════════════

    const DEMO_MIDI_B64 = '';
    const EXAMPLE_TONS = {"BGM01.TON": "", "KITFM.TON": "", "MUSIC.TON": "", "SE.TON": "", "SONG_07.TON": ""};

    // ═══════════════════════════════════════════════════════════════
    // TON SELECTOR (dropdown with embedded examples + load from disk)
    // ═══════════════════════════════════════════════════════════════

    /** @description Populate the TON file dropdown from the EXAMPLE_TONS dictionary. */
    function buildTonSelector() {
        const sel = document.getElementById('ton-select');
        sel.innerHTML = '<option value="">-- Select TON --</option>';
        // Add embedded example TON files
        for (const name of Object.keys(EXAMPLE_TONS)) {
            const opt = document.createElement('option');
            opt.value = 'embedded:' + name;
            opt.textContent = name;
            sel.appendChild(opt);
        }
    }


    /**
     * @description Import a TON bank via engine.importBank, update state instruments, and re-render.
     * @param {ArrayBuffer} arrayBuffer - Raw TON file data
     * @param {string} label - Display label for status message
     */
    function loadTonData(arrayBuffer, label) {
        if (playback.playing) playback.stop();
        var result = engine.importBank(arrayBuffer, label);
        if (result.instruments) {
            state.instruments = result.instruments;
        }
        showStatus(result.message);
        renderAll();
    }

    /** @description Handle TON dropdown selection; decodes embedded base64 TON and loads it.
     * @param {string} value - Selected option value (e.g. "embedded:filename") */
    async function onTonSelect(value) {
        if (!value) return;
        document.getElementById('ton-select').value = '';
        if (value.startsWith('embedded:')) {
            const name = value.slice(9);
            const b64 = EXAMPLE_TONS[name];
            if (!b64) return;
            await engine.init();
            engine.startAudio(playback);
            loadTonData(Uint8Array.from(atob(b64), c => c.charCodeAt(0)).buffer, name);
        }
    }


    /** @description Load the embedded demo MIDI (from DEMO_MIDI_B64) on startup and convert to tracker patterns. */
    function loadDemoMidi() {
        if (!DEMO_MIDI_B64) return;
        try {
            const bin = Uint8Array.from(atob(DEMO_MIDI_B64), c => c.charCodeAt(0));
            const midi = parseMIDI(bin.buffer);
            midiToPatterns(midi);
            showStatus('Loaded demo song (' + state.patterns.length + ' patterns)');
        } catch (err) {
            console.error('Demo MIDI load error:', err);
        }
    }

    // ═══════════════════════════════════════════════════════════════
    // MIDI KEYBOARD INPUT (Web MIDI API)
    // ═══════════════════════════════════════════════════════════════

    var midiAccess = null;
    var activeMidiInput = null;
    var midiLiveMode = false;
    var MIDI_LIVE_CH_BASE = 100;
    var midiLiveNotes = new Map();

    function onMidiMessage(e) {
        var data = e.data;
        var status = data[0], note = data[1], velocity = data[2];
        var cmd = status & 0xF0;
        var isNoteOn = cmd === 0x90 && velocity > 0;
        var isNoteOff = cmd === 0x80 || (cmd === 0x90 && velocity === 0);

        if (midiLiveMode) {
            if (isNoteOn) {
                engine.init().then(function() {
                    engine.startAudio(playback);
                    var ch = MIDI_LIVE_CH_BASE + (note % 16);
                    midiLiveNotes.set(note, ch);
                    engine.triggerNote(ch, note, selectedInst, state.instruments[selectedInst]);
                });
            } else if (isNoteOff && midiLiveNotes.has(note)) {
                engine.releaseChannel(midiLiveNotes.get(note));
                midiLiveNotes.delete(note);
            }
        }
    }

    function toggleMidiLive() {
        midiLiveMode = !midiLiveMode;
        var btn = document.getElementById('btn-midi-live');
        btn.classList.toggle('active', midiLiveMode);
        if (!midiLiveMode) {
            midiLiveNotes.forEach(function(ch) { engine.releaseChannel(ch); });
            midiLiveNotes.clear();
        }
    }

    function selectMidiInput(id) {
        if (activeMidiInput) {
            activeMidiInput.onmidimessage = null;
            activeMidiInput = null;
        }
        if (!id || !midiAccess) return;
        var input = midiAccess.inputs.get(id);
        if (input) {
            input.onmidimessage = onMidiMessage;
            activeMidiInput = input;
        }
    }

    function refreshMidiDevices() {
        var sel = document.getElementById('midi-input');
        if (!sel) return;
        var prevValue = sel.value;
        while (sel.options.length > 1) sel.remove(1);
        if (!midiAccess) return;
        midiAccess.inputs.forEach(function(input, id) {
            var opt = document.createElement('option');
            opt.value = id;
            opt.textContent = input.name;
            sel.appendChild(opt);
        });
        if (prevValue && midiAccess.inputs.has(prevValue)) {
            sel.value = prevValue;
            selectMidiInput(prevValue);
        } else if (activeMidiInput) {
            activeMidiInput = null;
            sel.value = '';
        }
    }

    function initMidi() {
        if (navigator.requestMIDIAccess) {
            navigator.requestMIDIAccess().then(function(access) {
                midiAccess = access;
                refreshMidiDevices();
                access.onstatechange = function() { refreshMidiDevices(); };
            }).catch(function(err) { console.warn('Web MIDI not available:', err); });
        } else {
            var sel = document.getElementById('midi-input');
            if (sel) {
                sel.options[0].textContent = '-- Not supported (use Chrome) --';
                sel.disabled = true;
            }
            var btn = document.getElementById('btn-midi-live');
            if (btn) btn.disabled = true;
        }
    }

    // ═══════════════════════════════════════════════════════════════
    // SELECTION CHANGE NOTIFICATIONS
    // ═══════════════════════════════════════════════════════════════

    function notifySelectionChange() {
        for (var i = 0; i < selectionChangeListeners.length; i++) {
            selectionChangeListeners[i](selectedInst, selectedOp);
        }
    }

    // ═══════════════════════════════════════════════════════════════
    // INIT
    // ═══════════════════════════════════════════════════════════════

    return {
        init: init,
        getSelectedInst: function() { return selectedInst; },
        setSelectedInst: function(v) { selectedInst = v; },
        getSelectedOp: function() { return selectedOp; },
        setSelectedOp: function(v) { selectedOp = v; },
        /** @description Register a listener called when instrument or operator selection changes.
         *  @param {function(number,number)} fn - callback(selectedInst, selectedOp) */
        onSelectionChange: function(fn) { selectionChangeListeners.push(fn); },
        renderInstEditor: renderInstEditor,
        renderInstList: renderInstList,
        renderChannelHeaders: renderChannelHeaders,
        showStatus: showStatus,
    };
})();
